import { ensureInteractivityPluginLoaded } from "@tsparticles/plugin-interactivity";
export { Drag } from "./Options/Classes/Drag.js";
import { Dragger } from "./Dragger.js";
export async function loadExternalDragInteraction(engine) {
    engine.checkVersion("4.1.1");
    await engine.pluginManager.register((e) => {
        ensureInteractivityPluginLoaded(e);
        e.pluginManager.addInteractor?.("externalDrag", container => {
            return Promise.resolve(new Dragger(container));
        });
    });
}
